Here's a complete sliding-window rate limiter middleware for Express. It uses a per-IP list of request timestamps and prunes expired ones on every request, which is what makes it a *true* sliding window (the cutoff moves continuously with `now`, rather than resetting at fixed interval boundaries).

```javascript
'use strict';

/**
 * Sliding-window rate limiting middleware for Express.
 *
 * True sliding window: every request prunes timestamps older than
 * (now - windowMs) and counts what remains. There is no fixed-interval
 * reset, so a client can never get a burst "for free" at a window boundary.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]    Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]   Max requests allowed per window.
 * @returns {Function} Express middleware, with a `.close()` method attached
 *                      to stop the background cleanup timer.
 */
function createRateLimiter(options = {}) {
  const windowMs = Number.isFinite(options.windowMs) ? options.windowMs : 60000;
  const maxRequests = Number.isFinite(options.maxRequests) ? options.maxRequests : 100;

  if (windowMs <= 0) throw new Error('windowMs must be a positive number');
  if (maxRequests <= 0) throw new Error('maxRequests must be a positive number');

  // Map<clientKey, number[]>  -> ascending list of request timestamps (ms).
  const hits = new Map();

  /**
   * Remove timestamps at or before `cutoff` from the front of a sorted array.
   * Timestamps are appended in chronological order, so expired ones are always
   * a contiguous prefix — we can splice the prefix in one shot.
   */
  function prune(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) i++;
    if (i > 0) timestamps.splice(0, i);
    return timestamps;
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;

    // NOTE on req.ip behind proxies (see longer note at bottom of file):
    // req.ip reflects the socket address unless Express "trust proxy" is set.
    // Behind a load balancer / reverse proxy you MUST configure trust proxy
    // (e.g. app.set('trust proxy', 1)) or every client collapses to one key.
    const key = req.ip || req.socket?.remoteAddress || 'unknown';

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    prune(timestamps, cutoff);

    if (timestamps.length >= maxRequests) {
      // Rejected. The oldest surviving timestamp is what must expire before
      // a slot frees up; that's the precise Retry-After for a sliding window.
      const oldest = timestamps[0];
      const retryAfterMs = oldest + windowMs - now;
      const retryAfterSec = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.setHeader('Retry-After', String(retryAfterSec));
      res.setHeader('X-RateLimit-Limit', String(maxRequests));
      res.setHeader('X-RateLimit-Remaining', '0');
      res.setHeader('X-RateLimit-Reset', String(Math.ceil((oldest + windowMs) / 1000)));

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Allowed. Record this request.
    timestamps.push(now);

    const remaining = Math.max(0, maxRequests - timestamps.length);
    // Reset = when the current oldest timestamp leaves the window. With a
    // sliding window there's no single "reset" instant, so we report the
    // moment the window would next have free capacity if no more requests come.
    const resetSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', String(maxRequests));
    res.setHeader('X-RateLimit-Remaining', String(remaining));
    res.setHeader('X-RateLimit-Reset', String(resetSec));

    next();
  };

  // --- Memory management -----------------------------------------------------
  // Periodically drop IPs that have no live timestamps. Without this, the Map
  // grows unbounded as new IPs appear (one-off clients never get cleaned up).
  const cleanup = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      prune(timestamps, cutoff);
      if (timestamps.length === 0) hits.delete(key);
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanup.unref === 'function') cleanup.unref();

  /** Stop the cleanup timer and release the in-memory store. */
  middleware.close = function close() {
    clearInterval(cleanup);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
```

### Usage example

