/**
 * slidingWindowRateLimiter.js
 *
 * True sliding window rate limiter middleware for Express.js.
 *
 * ─── PROXY / req.ip NOTE ──────────────────────────────────────────────────────
 * Express resolves req.ip from the raw TCP connection by default. When your app
 * runs behind a reverse proxy (Nginx, AWS ALB, Cloudflare, etc.) every request
 * appears to originate from the proxy, so all clients share one rate-limit bucket.
 *
 * Fix: configure Express to read the real client IP from X-Forwarded-For:
 *
 *   app.set('trust proxy', 1);           // trust one upstream proxy (most setups)
 *   app.set('trust proxy', 'loopback');  // trust loopback addresses (same host)
 *   app.set('trust proxy', 'X.X.X.X');  // trust a specific proxy IP
 *
 * Set this BEFORE attaching any rate-limiter middleware. For multiple hops
 * (CDN → load balancer → app), increment the hop count accordingly.
 * See https://expressjs.com/en/guide/behind-proxies.html for the full reference.
 * ─────────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * @typedef {object} RateLimiterOptions
 * @property {number} [windowMs=60000]
 *   Sliding window duration in milliseconds. Every request is measured against
 *   a window that ends *right now* and begins (now − windowMs) ago.
 * @property {number} [maxRequests=100]
 *   Maximum requests a single IP may make in any windowMs-wide interval.
 */

/**
 * @typedef {object} RateLimiter
 * @property {import('express').RequestHandler} middleware
 * @property {() => void} close  Stop the cleanup timer on graceful shutdown.
 */

// ─── Algorithm ────────────────────────────────────────────────────────────────
//
// Per-IP state: a chronologically ordered array of request timestamps (ms).
//
// On every request from IP X at time T:
//   1. windowStart = T − windowMs
//   2. Drop every timestamp ≤ windowStart  — these have "aged out"
//   3. If remaining count ≥ maxRequests    — reject (HTTP 429)
//   4. Otherwise push T, allow the request — window now has count+1 entries
//
// The window truly slides with the clock — no fixed epoch boundary that resets
// an entire cohort of clients at the same instant.
// ──────────────────────────────────────────────────────────────────────────────

/**
 * Creates a sliding window rate limiter.
 *
 * @param {RateLimiterOptions} [options]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // 1 minute
  const maxRequests = options.maxRequests ?? 100;

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new TypeError('options.windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests < 1) {
    throw new TypeError('options.maxRequests must be a positive integer');
  }

  // ── In-memory store ──────────────────────────────────────────────────────
  // Maps each client IP to its chronologically sorted request-timestamp array.
  // The array is append-only inside the middleware so it stays sorted for free.
  /** @type {Map<string, number[]>} */
  const store = new Map();

  // ── Background cleanup ───────────────────────────────────────────────────
  // Evicts fully-stale entries and trims residual old timestamps on active ones.
  // Runs every 60 s; the interval itself does not hold the process open (unref).
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;

    for (const [ip, timestamps] of store) {
      const firstFresh = findFirstIndexAfter(timestamps, cutoff);

      if (firstFresh === timestamps.length) {
        store.delete(ip);             // all timestamps stale → remove entry
      } else if (firstFresh > 0) {
        store.set(ip, timestamps.slice(firstFresh)); // trim leading stale entries
      }
    }
  }, 60_000);

  // Prevent the interval from keeping the Node.js process alive after all
  // other work finishes — critical for tests and short-lived scripts.
  cleanupInterval.unref?.();

  // ── Middleware ───────────────────────────────────────────────────────────
  /**
   * Express request handler.
   *
   * Allowed →  X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset
   * Rejected → HTTP 429 + Retry-After + JSON body
   *
   * @type {import('express').RequestHandler}
   */
  function middleware(req, res, next) {
    const ip  = req.ip ?? req.socket?.remoteAddress ?? 'unknown';
    const now = Date.now();

    // 1. Slide the window — discard anything older than windowMs ago
    const windowStart = now - windowMs;
    const raw         = store.get(ip) ?? [];
    const firstFresh  = findFirstIndexAfter(raw, windowStart);
    const timestamps  = firstFresh === 0 ? raw : raw.slice(firstFresh);

    // 2. Enforce the limit
    if (timestamps.length >= maxRequests) {
      // The oldest active timestamp tells us when the next slot opens up:
      // that request exits the window at (timestamps[0] + windowMs).
      const retryAfterMs   = (timestamps[0] + windowMs) - now;
      const retryAfterSecs = Math.ceil(retryAfterMs / 1_000);

      res.set('Retry-After', String(retryAfterSecs));
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSecs,
      });
    }

    // 3. Record and allow
    timestamps.push(now);
    store.set(ip, timestamps);

    // X-RateLimit-Reset = epoch second when the *oldest* slot in the current
    // window expires and the client gains back a request unit.
    const resetEpochSecs = Math.ceil((timestamps[0] + windowMs) / 1_000);
    const remaining      = maxRequests - timestamps.length;

    res.set('X-RateLimit-Limit',     String(maxRequests));
    res.set('X-RateLimit-Remaining', String(Math.max(0, remaining)));
    res.set('X-RateLimit-Reset',     String(resetEpochSecs));

    next();
  }

  // ── Lifecycle ────────────────────────────────────────────────────────────
  /** Stop the cleanup timer during graceful shutdown. */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

// ── Internal helpers ─────────────────────────────────────────────────────────

/**
 * Binary search: first index in `arr` where arr[i] > value.
 * Returns arr.length when all elements are ≤ value.
 * Requires `arr` sorted ascending — guaranteed by append-only writes.
 * O(log n) vs O(n) filter; matters when a single IP has thousands of timestamps.
 *
 * @param {number[]} arr
 * @param {number}   value
 * @returns {number}
 */
function findFirstIndexAfter(arr, value) {
  let lo = 0;
  let hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >>> 1; // unsigned shift avoids signed-int overflow
    if (arr[mid] <= value) lo = mid + 1;
    else                   hi = mid;
  }
  return lo;
}

module.exports = { createRateLimiter };
```

