const { createRateLimiter } = require('./slidingWindowRateLimiter');

const app = express();

// ── 1. Trust proxy — REQUIRED behind Nginx / any reverse proxy ──────────────
app.set('trust proxy', 1);

// ── 2. Global limiter: 100 req / 60 s per IP ────────────────────────────────
const globalLimiter = createRateLimiter({ windowMs: 60_000, maxRequests: 100 });
app.use(globalLimiter.middleware);

// ── 3. Stricter limiter on sensitive routes: 10 req / 15 min per IP ─────────
const authLimiter = createRateLimiter({ windowMs: 15 * 60_000, maxRequests: 10 });
