const express = require('express');
const { createRateLimiter } = require('./rate-limiter');

const app = express();

// CRITICAL: Configure trust proxy *before* using any IP-based middleware.
app.set('trust proxy', 1);

const limiter = createRateLimiter({
  windowMs: 60 * 1000,
  maxRequests: 100
});

app.use('/api', limiter);

app.get('/api/data', (req, res) => {
  res.json({ ok: true });
});

const server = app.listen(3000);

function shutdown() {
  limiter.close();           // stop cleanup timer
  server.close(() => process.exit(0));
}

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);
```

The file already implements:
- True sliding window (prunes old timestamps on every request, no fixed buckets)
- All required headers on allow + 429 + `Retry-After` on reject
- 60s cleanup interval + `close()` method
- Detailed `req.ip` / proxy note at the top
